import pulp

# Create the optimization model
model = pulp.LpProblem("LiquidBlending", pulp.LpMaximize)

# Data
raw_materials = ["A", "B", "C", "D"]
products = ["ProdA", "ProdB"]

sulfur = {
    "A": 0.03,
    "B": 0.01,
    "C": 0.02,
    "D": 0.01
}

purchase_price = {
    "A": 6,
    "B": 16,
    "C": 10,
    "D": 15
}

selling_price = {
    "ProdA": 9.15,
    "ProdB": 9.15
}

max_sulfur = {
    "ProdA": 0.025,
    "ProdB": 0.015
}

demand = {
    "ProdA": 100,
    "ProdB": 200
}

supply_D = 50

# Decision variables:
# x[i][p] = amount of raw material i used in product p
x = pulp.LpVariable.dicts("x", (raw_materials, products), lowBound=0, cat="Continuous")

# Intermediate production quantities
production = {
    p: pulp.lpSum(x[i][p] for i in raw_materials)
    for p in products
}

# Objective: maximize profit = revenue - raw material cost
model += (
    pulp.lpSum(selling_price[p] * production[p] for p in products)
    - pulp.lpSum(purchase_price[i] * x[i][p] for i in raw_materials for p in products)
), "Total_Profit"

# Demand constraints
for p in products:
    model += production[p] <= demand[p], f"Demand_{p}"

# Supply limit for raw material D
model += pulp.lpSum(x["D"][p] for p in products) <= supply_D, "Supply_D"

# Sulfur content constraints
for p in products:
    model += (
        pulp.lpSum(sulfur[i] * x[i][p] for i in raw_materials)
        <= max_sulfur[p] * production[p]
    ), f"Sulfur_{p}"

status = model.solve(pulp.PULP_CBC_CMD(msg=False, timeLimit=300))

import pulp as _pulp_footer
_status_str = _pulp_footer.LpStatus[status]
if _status_str == 'Optimal':
    print("Optimal value:", _pulp_footer.value(model.objective))
elif _status_str == 'Infeasible':
    print("Model is infeasible.")
elif _status_str == 'Unbounded':
    print("Model is unbounded.")
else:
    print("Other status:", _status_str)

