import pulp

# Data
products = ["A1", "A2", "A3"]

max_demand = {
    "A1": 5300,
    "A2": 4500,
    "A3": 5400,
}

selling_price = {
    "A1": 124,
    "A2": 109,
    "A3": 115,
}

production_cost = {
    "A1": 73.30,
    "A2": 52.90,
    "A3": 65.40,
}

production_quota = {
    "A1": 500,
    "A2": 450,
    "A3": 550,
}

activation_cost = {
    "A1": 170000,
    "A2": 150000,
    "A3": 100000,
}

min_batch = {
    "A1": 20,
    "A2": 20,
    "A3": 16,
}

available_days = 22

profit_per_unit = {
    p: selling_price[p] - production_cost[p]
    for p in products
}

# Model
model = pulp.LpProblem("CompleteProductionPlanning", pulp.LpMaximize)

# Decision variables
produce_qty = {
    p: pulp.LpVariable(f"produce_qty_{p}", lowBound=0, cat="Integer")
    for p in products
}

use_product = {
    p: pulp.LpVariable(f"use_product_{p}", cat="Binary")
    for p in products
}

# Objective: maximize total profit = variable profit - fixed activation costs
model += (
    pulp.lpSum(profit_per_unit[p] * produce_qty[p] for p in products)
    - pulp.lpSum(activation_cost[p] * use_product[p] for p in products)
)

# Total available production time (days)
model += (
    pulp.lpSum(produce_qty[p] / production_quota[p] for p in products)
    <= available_days,
    "TotalProductionTime",
)

# Product-specific constraints
for p in products:
    model += produce_qty[p] <= max_demand[p], f"MaxDemand_{p}"
    model += produce_qty[p] >= min_batch[p] * use_product[p], f"MinBatchLink_{p}"
    model += produce_qty[p] <= max_demand[p] * use_product[p], f"ActivationLink_{p}"

status = model.solve(pulp.PULP_CBC_CMD(msg=False, timeLimit=300))

import pulp as _pulp_footer
_status_str = _pulp_footer.LpStatus[status]
if _status_str == 'Optimal':
    print("Optimal value:", _pulp_footer.value(model.objective))
elif _status_str == 'Infeasible':
    print("Model is infeasible.")
elif _status_str == 'Unbounded':
    print("Model is unbounded.")
else:
    print("Other status:", _status_str)

description:
A company produces two types of products: microwave ovens and water heaters, which are manufactured in both workshops A and B. It is known that apart from the purchased parts, the production of one microwave oven requires 2 hours of processing in workshop A and 1 hour of assembly in workshop B. The production of one water heater requires 1 hour of processing in workshop A and 3 hours of assembly in workshop B. After production, both products need inspection, sales, and other procedures. The inspection and sales cost for each microwave oven is 30 yuan, and for each water heater is 50 yuan. Workshop A has 250 hours of available production time per month, with each hour costing 80 yuan; workshop B has 150 hours of available production time per month, with each hour costing 20 yuan. It is estimated that an average of 80 microwave ovens and 50 water heaters can be sold per month next year. Based on these actual conditions, the company has established the following monthly plan constraints:

1. Inspection and sales costs should not exceed 5500 yuan per month;
2. At least 80 microwave ovens should be sold per month;
3. The production hours of both workshops A and B should be fully utilized;
4. Overtime in workshop A should not exceed 20 hours;
5. At least 50 water heaters should be sold per month.

Try to determine the monthly production plan for the company.

