import pulp

# Data
hospitals = [1, 2, 3, 4]

initial_supply = {
    1: 480,
    2: 492,
    3: 74,
    4: 317
}

required_supply = {
    1: 61,
    2: 313,
    3: 93,
    4: 199
}

cost = {
    (1, 2): 8,  (1, 3): 42, (1, 4): 27,
    (2, 1): 17, (2, 3): 13, (2, 4): 30,
    (3, 1): 4,  (3, 2): 14, (3, 4): 16,
    (4, 1): 33, (4, 2): 9,  (4, 3): 42
}

arcs = list(cost.keys())

# Surplus available for shipment and deficit needing receipt
surplus = {h: max(0, initial_supply[h] - required_supply[h]) for h in hospitals}
deficit = {h: max(0, required_supply[h] - initial_supply[h]) for h in hospitals}

# Build model
model = pulp.LpProblem("Medical_Supplies_Transfer", pulp.LpMinimize)

# Only allow shipments from surplus hospitals to deficit hospitals
valid_arcs = [(i, j) for (i, j) in arcs if surplus[i] > 0 and deficit[j] > 0]

x = pulp.LpVariable.dicts("x", valid_arcs, lowBound=0, cat="Continuous")

# Objective
model += pulp.lpSum(cost[i, j] * x[i, j] for (i, j) in valid_arcs)

# Surplus hospitals can ship at most their surplus
for i in hospitals:
    if surplus[i] > 0:
        model += pulp.lpSum(x[i, j] for (ii, j) in valid_arcs if ii == i) <= surplus[i], f"surplus_cap_{i}"

# Deficit hospitals must receive exactly their deficit
for j in hospitals:
    if deficit[j] > 0:
        model += pulp.lpSum(x[i, j] for (i, jj) in valid_arcs if jj == j) == deficit[j], f"deficit_fill_{j}"

status = model.solve(pulp.PULP_CBC_CMD(msg=False, timeLimit=300))

import pulp as _pulp_footer
_status_str = _pulp_footer.LpStatus[status]
if _status_str == 'Optimal':
    print("Optimal value:", _pulp_footer.value(model.objective))
elif _status_str == 'Infeasible':
    print("Model is infeasible.")
elif _status_str == 'Unbounded':
    print("Model is unbounded.")
else:
    print("Other status:", _status_str)
